ESCALATE_TOOL = {
    "name": "escalate_to_human",
    "description": (
        "Call this tool when you cannot safely or correctly proceed autonomously. "
        "Use it for policy boundaries, unresolvable errors, ambiguous instructions "
        "with no safe default, required irreversible actions you are uncertain about, "
        "or safety concerns. Do NOT use it as a substitute for trying your tools "
        "correctly -- only escalate after exhausting autonomous options."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "reason": {
                "type": "string",
                "enum": [
                    "policy_boundary", "safety_concern", "irreversible_action",
                    "error_loop", "conflicting_requirements", "ambiguous_instructions",
                    "missing_context", "low_confidence", "novel_situation", "other",
                ],
            },
            "description": {
                "type": "string",
                "description": "Why you are escalating and what you need",
            },
            "attempted_actions": {
                "type": "array",
                "items": {"type": "string"},
                "description": "What you already tried",
            },
            "proposed_resolution": {
                "type": "string",
                "description": "What you would do if given authorisation or clarification",
            },
            "blocking": {
                "type": "boolean",
                "description": "True = cannot continue; False = can work on other subtasks while waiting",
                "default": True,
            },
        },
        "required": ["reason", "description"],
    },
}

async def run_agent_with_escalation(
    task:       str,
    tools:      list[dict],
    tool_fns:   dict[str, Callable[..., Awaitable[Any]]],
    notify:     Callable[[EscalationRecord], Awaitable[None]],
    session_id: str | None = None,
    max_steps:  int = 50,
) -> str:
    session_id = session_id or str(uuid.uuid4())
    all_tools  = tools + [ESCALATE_TOOL]
    messages   = [{"role": "user", "content": task}]

    for step in range(max_steps):
        response = await client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=2048,
            tools=all_tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next((b.text for b in response.content if hasattr(b, "text")), "")

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue

            if block.name == "escalate_to_human":
                result = await handle_escalate_tool(
                    session_id=session_id, notify=notify, **block.input
                )
            else:
                fn = tool_fns.get(block.name)
                if fn is None:
                    result = json.dumps({"error": f"unknown tool: {block.name}"})
                else:
                    try:
                        res = await fn(**block.input)
                        result = json.dumps(res) if not isinstance(res, str) else res
                    except Exception as exc:
                        result = json.dumps({"error": str(exc)})

            tool_results.append({
                "type": "tool_result", "tool_use_id": block.id, "content": result
            })

        messages.append({"role": "user", "content": tool_results})

    raise RuntimeError(f"Agent exceeded max_steps={max_steps}")

from fastapi import FastAPI
from fastapi.responses import JSONResponse
app = FastAPI()

@app.get("/escalations/{escalation_id}")
async def get_escalation(escalation_id: str):
    r = _escalations.get(escalation_id)
    if not r:
        return JSONResponse({"error": "not found"}, status_code=404)
    return JSONResponse({
        "escalation_id":      r.escalation_id,
        "priority":           r.priority,
        "reason":             r.reason,
        "description":        r.description,
        "attempted_actions":  r.attempted_actions,
        "proposed_resolution": r.proposed_resolution,
        "blocking":           r.blocking,
        "status":             r.status,
        "created_at":         r.created_at,
    })

@app.post("/escalations/{escalation_id}/resolve")
async def resolve_escalation(
    escalation_id:   str,
    resolution_type: str,   # "answer" | "takeover" | "abort"
    message:         str = "",
):
    r = _escalations.get(escalation_id)
    if not r or r.status != EscalationStatus.OPEN:
        return JSONResponse({"error": "not found or already resolved"}, status_code=400)

    if resolution_type == "abort":
        r.response = "Operator aborted this task."
        r.status   = EscalationStatus.RESOLVED
        r.event.set()
        return JSONResponse({"status": "aborted"})

    r.response = (
        f"Operator takeover complete. Result: {message}. Skip this action and continue."
        if resolution_type == "takeover" else (message or "Proceed as planned.")
    )
    r.status = EscalationStatus.RESOLVED
    r.event.set()
    return JSONResponse({"status": "resolved"})

@app.get("/escalations")
async def list_open_escalations():
    items = [
        {"escalation_id": r.escalation_id, "priority": r.priority,
         "reason": r.reason, "description": r.description[:100], "created_at": r.created_at}
        for r in _escalations.values() if r.status == EscalationStatus.OPEN
    ]
    items.sort(key=lambda x: x["priority"])
    return JSONResponse({"escalations": items})
